     1→/**
     2→ * PM Schedule Management Routes
     3→ *
     4→ * REST endpoints for PM schedule CRUD operations and history.
     5→ * Wraps PMSchedulerService with HTTP interface per spec 005.5.
     6→ *
     7→ * Endpoints:
     8→ * - GET /pm/schedule - List schedules with filtering
     9→ * - GET /pm/schedule/:id - Get PM by ID
    10→ * - POST /pm/schedule - Create new PM schedule
    11→ * - PATCH /pm/schedule/:id - Update PM (reschedule, reassign)
    12→ * - POST /pm/schedule/:id/validate-move - Validate PM move (real-time drag feedback)
    13→ * - POST /pm/schedule/:id/move-impact - Get impact assessment (confirmation dialog)
    14→ * - POST /pm/schedule/:id/lock - Lock PM to prevent optimizer changes
    15→ * - POST /pm/schedule/:id/unlock - Unlock PM to allow optimizer changes
    16→ * - GET /pm/schedule/:id/history - Get change history
    17→ *
    18→ * @see specs/005-api.md Section 5.5
    19→ */
    20→
    21→import { Hono } from 'hono';
    22→import { eq, and, gte, lte, isNull, count, desc } from 'drizzle-orm';
    23→import type { SQL } from 'drizzle-orm';
    24→import {
    25→  success,
    26→  paginatedSuccess,
    27→  error,
    28→  parsePaginationQuery,
    29→  ErrorCodes,
    30→  type AppVariables,
    31→} from '../types';
    32→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    33→import {
    34→  getPMSchedulerService,
    35→  getManHourLevelingService,
    36→  type SchedulePmRequest,
    37→  type MovePmRequest,
    38→} from '../../services';
    39→import { isValidUuid } from '../../lib/schemas';
    40→import { SYSTEM_USER_ID } from '../../lib/constants';
    41→import { db } from '../../lib/db/connection';
    42→import { pmSchedule } from '../../lib/db/schema';
    43→import { getWebSocketHub } from '../websocket';
    44→
    45→let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
    46→let manHourService: ReturnType<typeof getManHourLevelingService> | null = null;
    47→
    48→function getService(): ReturnType<typeof getPMSchedulerService> {
    49→  if (!pmSchedulerService) {
    50→    pmSchedulerService = getPMSchedulerService();
    51→  }
    52→  return pmSchedulerService;
    53→}
    54→
    55→function getManHourService(): ReturnType<typeof getManHourLevelingService> {
    56→  if (!manHourService) {
    57→    manHourService = getManHourLevelingService();
    58→  }
    59→  return manHourService;
    60→}
    61→
    62→export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    63→
    64→/**
    65→ * GET /pm/schedule
    66→ *
    67→ * List PM schedules with filtering and pagination.
    68→ *
    69→ * Query Parameters:
    70→ * - trainId: Filter by train
    71→ * - depotId: Filter by assigned depot
    72→ * - pmTypeId: Filter by PM type
    73→ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    74→ * - fromDate: Target date from (inclusive)
    75→ * - toDate: Target date to (inclusive)
    76→ * - scenarioId: Get scenario schedule (null/omitted = production)
    77→ */
    78→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    79→  // Parse query filters
    80→  const trainId = c.req.query('trainId');
    81→  const depotId = c.req.query('depotId');
    82→  const pmTypeId = c.req.query('pmTypeId');
    83→  const status = c.req.query('status');
    84→  const fromDate = c.req.query('fromDate');
    85→  const toDate = c.req.query('toDate');
    86→  const scenarioId = c.req.query('scenarioId');
    87→
    88→  // Build filter conditions
    89→  const conditions: SQL<unknown>[] = [];
    90→
    91→  if (trainId && isValidUuid(trainId)) {
    92→    conditions.push(eq(pmSchedule.trainId, trainId));
    93→  }
    94→  if (depotId && isValidUuid(depotId)) {
    95→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
    96→  }
    97→  if (pmTypeId && isValidUuid(pmTypeId)) {
    98→    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
    99→  }
   100→  if (status) {
   101→    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
   102→    if (validStatuses.includes(status as typeof validStatuses[number])) {
   103→      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
   104→    }
   105→  }
   106→  if (fromDate) {
   107→    conditions.push(gte(pmSchedule.targetDate, fromDate));
   108→  }
   109→  if (toDate) {
   110→    conditions.push(lte(pmSchedule.targetDate, toDate));
   111→  }
   112→
   113→  // Handle scenario filter
   114→  if (scenarioId && isValidUuid(scenarioId)) {
   115→    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
   116→  } else {
   117→    // Default to production schedule (scenarioId is NULL)
   118→    conditions.push(isNull(pmSchedule.scenarioId));
   119→  }
   120→
   121→  // Parse pagination
   122→  const pagination = parsePaginationQuery({
   123→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   124→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   125→    sort: c.req.query('sort'),
   126→  });
   127→
   128→  // Count total items
   129→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   130→  const totalResult = await db
   131→    .select({ count: count() })
   132→    .from(pmSchedule)
   133→    .where(whereClause);
   134→  const totalItems = totalResult[0]?.count ?? 0;
   135→
   136→  // Query with relations
   137→  const schedules = await db.query.pmSchedule.findMany({
   138→    where: whereClause,
   139→    with: {
   140→      train: {
   141→        with: {
   142→          fleet: true,
   143→        },
   144→      },
   145→      pmType: true,
   146→      assignedDepot: true,
   147→      assignedTrack: true,
   148→    },
   149→    orderBy: desc(pmSchedule.targetDate),
   150→    limit: pagination.pageSize,
   151→    offset: pagination.offset,
   152→  });
   153→
   154→  // Map to API response format
   155→  const data = schedules.map((pm) => ({
   156→    id: pm.id,
   157→    train: pm.train
   158→      ? {
   159→          id: pm.train.id,
   160→          trainNumber: pm.train.trainNumber,
   161→          fleetCode: pm.train.fleet?.code ?? null,
   162→        }
   163→      : null,
   164→    pmType: pm.pmType
   165→      ? {
   166→          id: pm.pmType.id,
   167→          code: pm.pmType.pmCode,
   168→          name: pm.pmType.pmName,
   169→          estimatedHours: pm.pmType.estimatedHours,
   170→        }
   171→      : null,
   172→    targetDate: pm.targetDate,
   173→    targetMileageKm: pm.targetMileageKm,
   174→    status: pm.status,
   175→    constraintStart: pm.constraintStart,
   176→    constraintEnd: pm.constraintEnd,
   177→    assignedDepot: pm.assignedDepot
   178→      ? {
   179→          id: pm.assignedDepot.id,
   180→          code: pm.assignedDepot.code,
   181→        }
   182→      : null,
   183→    assignedTrack: pm.assignedTrack
   184→      ? {
   185→          id: pm.assignedTrack.id,
   186→          trackNumber: pm.assignedTrack.trackNumber,
   187→          trackType: pm.assignedTrack.trackType,
   188→        }
   189→      : null,
   190→    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   191→    isLocked: pm.isLocked ?? false,
   192→    maximoWoId: pm.maximoWoId,
   193→  }));
   194→
   195→  return c.json(
   196→    paginatedSuccess(
   197→      data,
   198→      {
   199→        page: pagination.page,
   200→        pageSize: pagination.pageSize,
   201→        totalItems,
   202→      },
   203→      { durationMs: getRequestDuration(c) }
   204→    )
   205→  );
   206→});
   207→
   208→/**
   209→ * GET /pm/schedule/:id
   210→ *
   211→ * Get PM schedule details by ID.
   212→ */
   213→pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
   214→  const requestId = getRequestId(c);
   215→  const pmId = c.req.param('id');
   216→
   217→  if (!isValidUuid(pmId)) {
   218→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   219→  }
   220→
   221→  const service = getService();
   222→  const pmResult = await service.getPm(pmId);
   223→
   224→  // Cast to include all query relations (service returns more than type declares)
   225→  const pm = pmResult as typeof pmResult & {
   226→    assignedDepot: { id: string; code: string; name: string } | null;
   227→  };
   228→
   229→  // Check material availability for upcoming PMs
   230→  let materialStatus = { allAvailable: true, warnings: [] as string[] };
   231→  if (pm.status === 'SCHEDULED' && pm.assignedDepotId) {
   232→    try {
   233→      const materialResult = await service.checkMaterialAvailability(
   234→        pm.pmTypeId,
   235→        pm.assignedDepotId,
   236→        pm.targetDate
   237→      );
   238→      materialStatus = {
   239→        allAvailable: !materialResult.isBlocked && materialResult.softConstraintWarnings.length === 0,
   240→        warnings: [
   241→          ...materialResult.hardConstraintViolations.map((v) => `Blocked: ${v.partNumber} (need ${v.requiredQuantity}, have ${v.availableQuantity})`),
   242→          ...materialResult.softConstraintWarnings.map((v) => `Warning: ${v.partNumber} may not be available`),
   243→        ],
   244→      };
   245→    } catch {
   246→      // Material check failed, assume available
   247→    }
   248→  }
   249→
   250→  return c.json(
   251→    success({
   252→      id: pm.id,
   253→      train: pm.train
   254→        ? {
   255→            id: pm.train.id,
   256→            trainNumber: pm.train.trainNumber,
   257→            fleetId: pm.train.fleetId,
   258→          }
   259→        : null,
   260→      pmType: pm.pmType
   261→        ? {
   262→            id: pm.pmType.id,
   263→            code: pm.pmType.pmCode,
   264→            name: pm.pmType.pmName,
   265→            estimatedHours: pm.pmType.estimatedHours,
   266→          }
   267→        : null,
   268→      targetDate: pm.targetDate,
   269→      targetMileageKm: pm.targetMileageKm,
   270→      status: pm.status,
   271→      constraintStart: pm.constraintStart,
   272→      constraintEnd: pm.constraintEnd,
   273→      assignedDepot: pm.assignedDepot
   274→        ? {
   275→            id: pm.assignedDepot.id,
   276→            code: pm.assignedDepot.code,
   277→            name: pm.assignedDepot.name,
   278→          }
   279→        : null,
   280→      assignedTrack: pm.assignedTrack
   281→        ? {
   282→            id: pm.assignedTrack.id,
   283→            trackNumber: pm.assignedTrack.trackNumber,
   284→            trackType: pm.assignedTrack.trackType,
   285→          }
   286→        : null,
   287→      assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   288→      assignedShift: pm.assignedShift,
   289→      isLocked: pm.isLocked ?? false,
   290→      lockedReason: pm.lockedReason,
   291→      maximoWoId: pm.maximoWoId,
   292→      materialStatus,
   293→      actualStartDate: pm.actualStartDate,
   294→      actualEndDate: pm.actualEndDate,
   295→      actualHours: pm.actualHours ? Number(pm.actualHours) : null,
   296→      completedAt: pm.completedAt,
   297→      completedMileageKm: pm.completedMileageKm,
   298→      createdAt: pm.createdAt,
   299→      updatedAt: pm.updatedAt,
   300→    })
   301→  );
   302→});
   303→
   304→/**
   305→ * POST /pm/schedule
   306→ *
   307→ * Create a new PM schedule entry.
   308→ *
   309→ * Request body:
   310→ * - trainId: UUID of train
   311→ * - pmTypeId: UUID of PM type
   312→ * - targetDate: Target date (YYYY-MM-DD)
   313→ * - assignedDepotId?: UUID of assigned depot
   314→ * - assignedTrackId?: UUID of assigned track
   315→ * - scenarioId?: UUID of scenario (null for production)
   316→ * - reason?: Reason for manual scheduling
   317→ */
   318→pmScheduleRoutes.post('/pm/schedule', async (c) => {
   319→  const requestId = getRequestId(c);
   320→  const body = await c.req.json();
   321→
   322→  // Validate required fields
   323→  if (!body.trainId || !isValidUuid(body.trainId)) {
   324→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'trainId is required and must be a valid UUID', requestId), 400);
   325→  }
   326→  if (!body.pmTypeId || !isValidUuid(body.pmTypeId)) {
   327→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'pmTypeId is required and must be a valid UUID', requestId), 400);
   328→  }
   329→  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   330→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
   331→  }
   332→
   333→  // Validate optional UUIDs
   334→  if (body.assignedDepotId && !isValidUuid(body.assignedDepotId)) {
   335→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedDepotId must be a valid UUID', requestId), 400);
   336→  }
   337→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   338→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   339→  }
   340→
   341→  const service = getService();
   342→  const user = c.get('user');
   343→
   344→  const request: SchedulePmRequest = {
   345→    trainId: body.trainId,
   346→    pmTypeId: body.pmTypeId,
   347→    targetDate: body.targetDate,
   348→    assignedDepotId: body.assignedDepotId,
   349→    assignedTrackId: body.assignedTrackId,
   350→    assignedShift: body.assignedShift,
   351→    notes: body.reason,
   352→    createdBy: user?.id,
   353→  };
   354→
   355→  const created = await service.schedulePm(request);
   356→
   357→  return c.json(
   358→    success({
   359→      id: created.id,
   360→      trainId: created.trainId,
   361→      pmTypeId: created.pmTypeId,
   362→      targetDate: created.targetDate,
   363→      targetMileageKm: created.targetMileageKm,
   364→      status: created.status,
   365→      constraintStart: created.constraintStart,
   366→      constraintEnd: created.constraintEnd,
   367→      assignedDepotId: created.assignedDepotId,
   368→      assignedTrackId: created.assignedTrackId,
   369→      assignedHours: created.assignedHours ? Number(created.assignedHours) : null,
   370→      createdAt: created.createdAt,
   371→    }),
   372→    201
   373→  );
   374→});
   375→
   376→/**
   377→ * PATCH /pm/schedule/:id
   378→ *
   379→ * Update a PM schedule entry (move, reassign).
   380→ *
   381→ * Request body:
   382→ * - targetDate?: New target date
   383→ * - assignedTrackId?: New track assignment
   384→ * - reason: Reason for change (required)
   385→ */
   386→pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   387→  const requestId = getRequestId(c);
   388→  const pmId = c.req.param('id');
   389→
   390→  if (!isValidUuid(pmId)) {
   391→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   392→  }
   393→
   394→  const body = await c.req.json();
   395→
   396→  // Validate reason is provided
   397→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   398→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   399→  }
   400→
   401→  // Validate targetDate if provided
   402→  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   403→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   404→  }
   405→
   406→  // Validate assignedTrackId if provided
   407→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   408→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   409→  }
   410→
   411→  const service = getService();
   412→  const user = c.get('user');
   413→
   414→  // Get current PM to capture old values
   415→  const currentPm = await service.getPm(pmId);
   416→
   417→  // Only proceed if targetDate is being changed
   418→  if (!body.targetDate) {
   419→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
   420→  }
   421→
   422→  const request: MovePmRequest = {
   423→    pmScheduleId: pmId,
   424→    newTargetDate: body.targetDate,
   425→    newTrackId: body.assignedTrackId,
   426→    reason: body.reason,
   427→    movedBy: user?.id ?? SYSTEM_USER_ID,
   428→  };
   429→
   430→  const updated = await service.movePm(request);
   431→
   432→  // Calculate impact assessment
   433→  let manhourImpact = 0;
   434→  let conflictsCreated = 0;
   435→
   436→  // Calculate man-hour impact if depot is assigned
   437→  const depotId = updated.assignedDepotId ?? currentPm.assignedDepotId;
   438→  if (depotId) {
   439→    const estimatedHours = parseFloat(currentPm.pmType?.estimatedHours ?? '0');
   440→    const manHourSvc = getManHourService();
   441→
   442→    // Get old and new week utilization
   443→    // When PM moves, it removes hours from old week and adds to new week
   444→    const [oldWeekCapacity, newWeekCapacity] = await Promise.all([
   445→      manHourSvc.checkLaborCapacity(depotId, currentPm.targetDate, 0),
   446→      manHourSvc.checkLaborCapacity(depotId, updated.targetDate, estimatedHours),
   447→    ]);
   448→
   449→    // Impact is the change in new week's utilization
   450→    // Positive = increased load, Negative = decreased load
   451→    manhourImpact = Math.round(
   452→      (newWeekCapacity.utilizationPct - oldWeekCapacity.utilizationPct) * 100
   453→    ) / 100;
   454→  }
   455→
   456→  // Conflicts check: movePm already validates and throws on track conflicts
   457→  // If we reach here, no new conflicts were created
   458→  // The value 0 is correct - if there were conflicts, movePm would have thrown
   459→  conflictsCreated = 0;
   460→
   461→  const impactAssessment = {
   462→    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
   463→      ? 'WITHIN_WINDOW'
   464→      : 'OUTSIDE_WINDOW',
   465→    manhourImpact,
   466→    conflictsCreated,
   467→  };
   468→
   469→  // Broadcast PM update to all connected canvas subscribers
   470→  const hub = getWebSocketHub();
   471→  hub.broadcastPmUpdated({
   472→    pmId: updated.id,
   473→    trainId: updated.trainId,
   474→    trainNumber: currentPm.train?.trainNumber ?? 'Unknown',
   475→    changes: [
   476→      { field: 'targetDate', oldValue: currentPm.targetDate, newValue: updated.targetDate },
   477→      ...(body.assignedTrackId && body.assignedTrackId !== currentPm.assignedTrackId
   478→        ? [{ field: 'assignedTrackId', oldValue: currentPm.assignedTrackId, newValue: body.assignedTrackId }]
   479→        : []),
   480→    ],
   481→    changedBy: {
   482→      userId: user?.id ?? SYSTEM_USER_ID,
   483→      displayName: user?.email ?? 'System',
   484→    },
   485→  });
   486→
   487→  return c.json(
   488→    success({
   489→      id: updated.id,
   490→      targetDate: updated.targetDate,
   491→      previousTargetDate: currentPm.targetDate,
   492→      assignedTrackId: updated.assignedTrackId,
   493→      previousTrackId: currentPm.assignedTrackId,
   494→      updatedAt: updated.updatedAt,
   495→      updatedBy: user?.id,
   496→      explanation: {
   497→        changeType: 'DATE_CHANGED',
   498→        reason: body.reason,
   499→        impactAssessment,
   500→      },
   501→    })
   502→  );
   503→});
   504→
   505→/**
   506→ * POST /pm/schedule/:id/validate-move
   507→ *
   508→ * Validate a PM move without committing changes.
   509→ * Returns constraint violations for real-time drag feedback.
   510→ *
   511→ * Request body:
   512→ * - targetDate: New target date (YYYY-MM-DD)
   513→ * - trainId: Train ID (for service demand check)
   514→ */
   515→pmScheduleRoutes.post('/pm/schedule/:id/validate-move', async (c) => {
   516→  const requestId = getRequestId(c);
   517→  const pmId = c.req.param('id');
   518→
   519→  if (!isValidUuid(pmId)) {
   520→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   521→  }
   522→
   523→  const body = await c.req.json();
   524→
   525→  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   526→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
   527→  }
   528→
   529→  const service = getService();
   530→  const violations: Array<{
   531→    type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
   532→    severity: 'ERROR' | 'WARNING';
   533→    message: string;
   534→  }> = [];
   535→
   536→  try {
   537→    // Get existing PM with relations
   538→    const pm = await service.getPm(pmId);
   539→    const targetDate = body.targetDate;
   540→
   541→    // 1. Check Maximo lock
   542→    const lockStatus = await service.checkMaximoLock(pmId);
   543→    if (lockStatus.isLocked) {
   544→      violations.push({
   545→        type: 'MAXIMO_LOCK',
   546→        severity: 'ERROR',
   547→        message: lockStatus.reason ?? 'PM is locked and cannot be moved',
   548→      });
   549→    }
   550→
   551→    // 2. Check PM status
   552→    if (pm.status !== 'SCHEDULED') {
   553→      violations.push({
   554→        type: 'MAXIMO_LOCK',
   555→        severity: 'ERROR',
   556→        message: `PM cannot be moved: status is ${pm.status}`,
   557→      });
   558→    }
   559→
   560→    // 3. Check compliance window
   561→    if (targetDate < pm.constraintStart) {
   562→      violations.push({
   563→        type: 'COMPLIANCE_WINDOW',
   564→        severity: 'ERROR',
   565→        message: `Target date ${targetDate} is before compliance window start (${pm.constraintStart})`,
   566→      });
   567→    }
   568→
   569→    if (targetDate > pm.constraintEnd) {
   570→      violations.push({
   571→        type: 'COMPLIANCE_WINDOW',
   572→        severity: 'ERROR',
   573→        message: `Target date ${targetDate} is after compliance window end (${pm.constraintEnd})`,
   574→      });
   575→    }
   576→
   577→    // 4. Check track conflict (if track is assigned)
   578→    if (pm.assignedTrackId) {
   579→      const durationDays = pm.pmType?.minTrackDays ?? 1;
   580→      const conflict = await service.checkTrackConflict(
   581→        pm.assignedTrackId,
   582→        targetDate,
   583→        durationDays,
   584→        pmId
   585→      );
   586→
   587→      if (conflict) {
   588→        violations.push({
   589→          type: 'TRACK_CONFLICT',
   590→          severity: 'WARNING',
   591→          message: `Track is occupied on ${targetDate} by another PM`,
   592→        });
   593→      }
   594→    }
   595→
   596→    // 5. Check material availability (if depot assigned)
   597→    if (pm.assignedDepotId) {
   598→      const materialResult = await service.checkMaterialAvailability(
   599→        pm.pmTypeId,
   600→        pm.assignedDepotId,
   601→        targetDate
   602→      );
   603→
   604→      if (materialResult.isBlocked) {
   605→        const missingParts = materialResult.hardConstraintViolations
   606→          .map((v) => v.partNumber)
   607→          .join(', ');
   608→        violations.push({
   609→          type: 'MATERIAL',
   610→          severity: 'ERROR',
   611→          message: `Missing critical parts: ${missingParts}`,
   612→        });
   613→      } else if (materialResult.softConstraintWarnings.length > 0) {
   614→        violations.push({
   615→          type: 'MATERIAL',
   616→          severity: 'WARNING',
   617→          message: `${materialResult.softConstraintWarnings.length} parts may not be available`,
   618→        });
   619→      }
   620→    }
   621→
   622→    // 6. Check service demand (need serviceDemandService)
   623→    // Service demand is checked by the pm-scheduler service internally
   624→    // For validation, we import and use it here
   625→    const trainId = body.trainId ?? pm.trainId;
   626→    const { getServiceDemandService } = await import('../../services');
   627→    const serviceDemandService = getServiceDemandService();
   628→    const { canSchedule, validation } = await serviceDemandService.canScheduleTrainForMaintenance(
   629→      trainId,
   630→      targetDate
   631→    );
   632→
   633→    if (!canSchedule) {
   634→      violations.push({
   635→        type: 'SERVICE_DEMAND',
   636→        severity: 'ERROR',
   637→        message: validation.message,
   638→      });
   639→    }
   640→
   641→    const hasErrors = violations.some((v) => v.severity === 'ERROR');
   642→
   643→    return c.json(
   644→      success({
   645→        isValid: !hasErrors,
   646→        violations,
   647→      })
   648→    );
   649→  } catch (err) {
   650→    // If PM not found or other error
   651→    const message = err instanceof Error ? err.message : 'Validation failed';
   652→    return c.json(error(ErrorCodes.NOT_FOUND, message, requestId), 404);
   653→  }
   654→});
   655→
   656→/**
   657→ * POST /pm/schedule/:id/move-impact
   658→ *
   659→ * Get detailed impact assessment for a PM move.
   660→ * Used for the confirmation dialog before committing.
   661→ *
   662→ * Request body:
   663→ * - targetDate: New target date (YYYY-MM-DD)
   664→ * - currentDate: Current target date (YYYY-MM-DD)
   665→ */
   666→pmScheduleRoutes.post('/pm/schedule/:id/move-impact', async (c) => {
   667→  const requestId = getRequestId(c);
   668→  const pmId = c.req.param('id');
   669→
   670→  if (!isValidUuid(pmId)) {
   671→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   672→  }
   673→
   674→  const body = await c.req.json();
   675→
   676→  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   677→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
   678→  }
   679→
   680→  if (!body.currentDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.currentDate)) {
   681→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'currentDate is required and must be in YYYY-MM-DD format', requestId), 400);
   682→  }
   683→
   684→  const service = getService();
   685→  const manHourSvc = getManHourService();
   686→
   687→  try {
   688→    const pm = await service.getPm(pmId);
   689→    const targetDate = body.targetDate;
   690→    const currentDate = body.currentDate;
   691→
   692→    // Calculate man-hour changes
   693→    const depotId = pm.assignedDepotId;
   694→    const estimatedHours = parseFloat(pm.pmType?.estimatedHours ?? '0');
   695→
   696→    let manhourChange = {
   697→      sourceWeek: { required: 0, available: 0 },
   698→      targetWeek: { required: 0, available: 0 },
   699→    };
   700→
   701→    if (depotId) {
   702→      // Get source week capacity (current date, removing the PM hours)
   703→      const sourceWeek = await manHourSvc.checkLaborCapacity(depotId, currentDate, 0);
   704→
   705→      // Get target week capacity (new date, adding the PM hours)
   706→      const targetWeek = await manHourSvc.checkLaborCapacity(depotId, targetDate, estimatedHours);
   707→
   708→      manhourChange = {
   709→        sourceWeek: {
   710→          required: Math.round(sourceWeek.totalRequiredHours - estimatedHours),
   711→          available: sourceWeek.availableHours.total,
   712→        },
   713→        targetWeek: {
   714→          required: Math.round(targetWeek.totalRequiredHours),
   715→          available: targetWeek.availableHours.total,
   716→        },
   717→      };
   718→    }
   719→
   720→    // Calculate cost change (based on labor hours and rate)
   721→    // Simple estimate: same PM, no cost change unless overtime required
   722→    const targetUtilization = manhourChange.targetWeek.available > 0
   723→      ? manhourChange.targetWeek.required / manhourChange.targetWeek.available
   724→      : 0;
   725→    const overtimeThreshold = 0.9; // 90% utilization triggers overtime
   726→    const overtimeRate = 1.5; // 50% premium
   727→    const hourlyRate = 350; // HKD per hour (configurable)
   728→
   729→    let costChange = 0;
   730→    if (targetUtilization > overtimeThreshold && manhourChange.targetWeek.available > 0) {
   731→      // Overtime hours needed
   732→      const overtimeHours = Math.max(
   733→        0,
   734→        manhourChange.targetWeek.required - (manhourChange.targetWeek.available * overtimeThreshold)
   735→      );
   736→      costChange = Math.round(overtimeHours * hourlyRate * (overtimeRate - 1));
   737→    }
   738→
   739→    // Check for track conflicts created
   740→    const conflictsCreated: string[] = [];
   741→    if (pm.assignedTrackId) {
   742→      const durationDays = pm.pmType?.minTrackDays ?? 1;
   743→      const conflict = await service.checkTrackConflict(
   744→        pm.assignedTrackId,
   745→        targetDate,
   746→        durationDays,
   747→        pmId
   748→      );
   749→
   750→      if (conflict) {
   751→        conflictsCreated.push(`Track conflict with PM ${conflict.id} on ${conflict.targetDate}`);
   752→      }
   753→    }
   754→
   755→    // Calculate drift from baseline (if baseline exists)
   756→    let driftFromBaseline = 0;
   757→    try {
   758→      // Query for the most recent published baseline that includes this PM's train and PM type
   759→      const { baselinePmSchedule, planBaselines } = await import('../../lib/db/schema');
   760→
   761→      // Find latest published baseline
   762→      const latestBaseline = await db.query.planBaselines.findFirst({
   763→        where: eq(planBaselines.status, 'PUBLISHED'),
   764→        orderBy: desc(planBaselines.publishedAt),
   765→      });
   766→
   767→      if (latestBaseline) {
   768→        // Find this PM's baseline entry
   769→        const baselineEntry = await db.query.baselinePmSchedule.findFirst({
   770→          where: and(
   771→            eq(baselinePmSchedule.baselineId, latestBaseline.id),
   772→            eq(baselinePmSchedule.trainId, pm.trainId),
   773→            eq(baselinePmSchedule.pmTypeId, pm.pmTypeId)
   774→          ),
   775→        });
   776→
   777→        if (baselineEntry && baselineEntry.projectedDate) {
   778→          const baselineDateObj = new Date(baselineEntry.projectedDate);
   779→          const targetDateObj = new Date(targetDate);
   780→          driftFromBaseline = Math.round(
   781→            (targetDateObj.getTime() - baselineDateObj.getTime()) / (1000 * 60 * 60 * 24)
   782→          );
   783→        }
   784→      }
   785→    } catch {
   786→      // Baseline check failed, default to 0 drift
   787→      driftFromBaseline = 0;
   788→    }
   789→
   790→    return c.json(
   791→      success({
   792→        manhourChange,
   793→        costChange,
   794→        conflictsCreated,
   795→        driftFromBaseline,
   796→      })
   797→    );
   798→  } catch (err) {
   799→    const message = err instanceof Error ? err.message : 'Impact assessment failed';
   800→    return c.json(error(ErrorCodes.NOT_FOUND, message, requestId), 404);
   801→  }
   802→});
   803→
   804→/**
   805→ * POST /pm/schedule/:id/lock
   806→ *
   807→ * Lock a PM to prevent optimizer changes.
   808→ *
   809→ * Request body:
   810→ * - reason: Reason for locking (required)
   811→ */
   812→pmScheduleRoutes.post('/pm/schedule/:id/lock', async (c) => {
   813→  const requestId = getRequestId(c);
   814→  const pmId = c.req.param('id');
   815→
   816→  if (!isValidUuid(pmId)) {
   817→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   818→  }
   819→
   820→  const body = await c.req.json();
   821→
   822→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   823→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for locking', requestId), 400);
   824→  }
   825→
   826→  const service = getService();
   827→  const user = c.get('user');
   828→
   829→  // Get PM with train details for broadcast
   830→  const pm = await service.getPm(pmId);
   831→
   832→  const updated = await service.lockPm(pmId, body.reason, user?.id ?? SYSTEM_USER_ID);
   833→
   834→  // Broadcast lock event to all connected canvas subscribers
   835→  const hub = getWebSocketHub();
   836→  hub.broadcastPmLocked({
   837→    pmId: updated.id,
   838→    trainId: pm.trainId,
   839→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   840→    isLocked: true,
   841→    lockedReason: body.reason,
   842→    lockedBy: {
   843→      userId: user?.id ?? SYSTEM_USER_ID,
   844→      displayName: user?.email ?? 'System',
   845→    },
   846→  });
   847→
   848→  return c.json(
   849→    success({
   850→      id: updated.id,
   851→      isLocked: updated.isLocked,
   852→      lockedReason: updated.lockedReason,
   853→      lockedBy: updated.lockedBy,
   854→      lockedAt: updated.lockedAt,
   855→    })
   856→  );
   857→});
   858→
   859→/**
   860→ * POST /pm/schedule/:id/unlock
   861→ *
   862→ * Unlock a PM to allow optimizer changes.
   863→ */
   864→pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
   865→  const requestId = getRequestId(c);
   866→  const pmId = c.req.param('id');
   867→
   868→  if (!isValidUuid(pmId)) {
   869→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   870→  }
   871→
   872→  const service = getService();
   873→  const user = c.get('user');
   874→
   875→  // Get PM with train details for broadcast
   876→  const pm = await service.getPm(pmId);
   877→
   878→  const updated = await service.unlockPm(pmId, user?.id ?? SYSTEM_USER_ID);
   879→
   880→  // Broadcast unlock event to all connected canvas subscribers
   881→  const hub = getWebSocketHub();
   882→  hub.broadcastPmLocked({
   883→    pmId: updated.id,
   884→    trainId: pm.trainId,
   885→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   886→    isLocked: false,
   887→    lockedBy: {
   888→      userId: user?.id ?? SYSTEM_USER_ID,
   889→      displayName: user?.email ?? 'System',
   890→    },
   891→  });
   892→
   893→  return c.json(
   894→    success({
   895→      id: updated.id,
   896→      isLocked: updated.isLocked,
   897→      lockedReason: updated.lockedReason,
   898→      lockedBy: updated.lockedBy,
   899→      lockedAt: updated.lockedAt,
   900→    })
   901→  );
   902→});
   903→
   904→/**
   905→ * GET /pm/schedule/:id/history
   906→ *
   907→ * Get change history for a PM.
   908→ */
   909→pmScheduleRoutes.get('/pm/schedule/:id/history', async (c) => {
   910→  const requestId = getRequestId(c);
   911→  const pmId = c.req.param('id');
   912→
   913→  if (!isValidUuid(pmId)) {
   914→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   915→  }
   916→
   917→  const service = getService();
   918→  const history = await service.getPmHistory(pmId);
   919→
   920→  const data = history.map((entry) => ({
   921→    id: entry.id,
   922→    changeType: entry.changeType,
   923→    oldTargetDate: entry.oldTargetDate,
   924→    newTargetDate: entry.newTargetDate,
   925→    oldStatus: entry.oldStatus,
   926→    newStatus: entry.newStatus,
   927→    oldAssignedTrackId: entry.oldAssignedTrackId,
   928→    newAssignedTrackId: entry.newAssignedTrackId,
   929→    changedBy: entry.changedByUser
   930→      ? {
   931→          id: entry.changedByUser.id,
   932→          displayName: entry.changedByUser.displayName,
   933→        }
   934→      : null,
   935→    changedAt: entry.changedAt,
   936→    changeReason: entry.changeReason,
   937→    changeSource: entry.changeSource,
   938→  }));
   939→
   940→  return c.json(success(data));
   941→});
