/**
 * PM Schedule Management Routes
 *
 * REST endpoints for PM schedule CRUD operations and history.
 * Wraps PMSchedulerService with HTTP interface per spec 005.5.
 *
 * Endpoints:
 * - GET /pm/schedule - List schedules with filtering
 * - GET /pm/schedule/:id - Get PM by ID
 * - POST /pm/schedule - Create new PM schedule
 * - PATCH /pm/schedule/:id - Update PM (reschedule, reassign)
 * - POST /pm/schedule/:id/validate-move - Validate PM move (real-time drag feedback)
 * - POST /pm/schedule/:id/move-impact - Get impact assessment (confirmation dialog)
 * - POST /pm/schedule/:id/lock - Lock PM to prevent optimizer changes
 * - POST /pm/schedule/:id/unlock - Unlock PM to allow optimizer changes
 * - GET /pm/schedule/:id/history - Get change history
 *
 * @see specs/005-api.md Section 5.5
 */

import { Hono } from 'hono';
import { eq, and, gte, lte, isNull, count, desc } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getPMSchedulerService,
  getManHourLevelingService,
  type SchedulePmRequest,
  type MovePmRequest,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';
import { SYSTEM_USER_ID } from '../../lib/constants';
import { db } from '../../lib/db/connection';
import { pmSchedule } from '../../lib/db/schema';
import { getWebSocketHub } from '../websocket';

let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
let manHourService: ReturnType<typeof getManHourLevelingService> | null = null;

function getService(): ReturnType<typeof getPMSchedulerService> {
  if (!pmSchedulerService) {
    pmSchedulerService = getPMSchedulerService();
  }
  return pmSchedulerService;
}

function getManHourService(): ReturnType<typeof getManHourLevelingService> {
  if (!manHourService) {
    manHourService = getManHourLevelingService();
  }
  return manHourService;
}

export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /pm/schedule
 *
 * List PM schedules with filtering and pagination.
 *
 * Query Parameters:
 * - trainId: Filter by train
 * - depotId: Filter by assigned depot
 * - pmTypeId: Filter by PM type
 * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
 * - fromDate: Target date from (inclusive)
 * - toDate: Target date to (inclusive)
 * - scenarioId: Get scenario schedule (null/omitted = production)
 */
pmScheduleRoutes.get('/pm/schedule', async (c) => {
  // Parse query filters
  const trainId = c.req.query('trainId');
  const depotId = c.req.query('depotId');
  const pmTypeId = c.req.query('pmTypeId');
  const status = c.req.query('status');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');
  const scenarioId = c.req.query('scenarioId');

  // Build filter conditions
  const conditions: SQL<unknown>[] = [];

  if (trainId && isValidUuid(trainId)) {
    conditions.push(eq(pmSchedule.trainId, trainId));
  }
  if (depotId && isValidUuid(depotId)) {
    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
  }
  if (pmTypeId && isValidUuid(pmTypeId)) {
    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
  }
  if (status) {
    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
    if (validStatuses.includes(status as typeof validStatuses[number])) {
      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
    }
  }
  if (fromDate) {
    conditions.push(gte(pmSchedule.targetDate, fromDate));
  }
  if (toDate) {
    conditions.push(lte(pmSchedule.targetDate, toDate));
  }

  // Handle scenario filter
  if (scenarioId && isValidUuid(scenarioId)) {
    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
  } else {
    // Default to production schedule (scenarioId is NULL)
    conditions.push(isNull(pmSchedule.scenarioId));
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  // Count total items
  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
  const totalResult = await db
    .select({ count: count() })
    .from(pmSchedule)
    .where(whereClause);
  const totalItems = totalResult[0]?.count ?? 0;

  // Query with relations
  const schedules = await db.query.pmSchedule.findMany({
    where: whereClause,
    with: {
      train: {
        with: {
          fleet: true,
        },
      },
      pmType: true,
      assignedDepot: true,
      assignedTrack: true,
    },
    orderBy: desc(pmSchedule.targetDate),
    limit: pagination.pageSize,
    offset: pagination.offset,
  });

  // Map to API response format
  const data = schedules.map((pm) => ({
    id: pm.id,
    train: pm.train
      ? {
          id: pm.train.id,
          trainNumber: pm.train.trainNumber,
          fleetCode: pm.train.fleet?.code ?? null,
        }
      : null,
    pmType: pm.pmType
      ? {
          id: pm.pmType.id,
          code: pm.pmType.pmCode,
          name: pm.pmType.pmName,
          estimatedHours: pm.pmType.estimatedHours,
        }
      : null,
    targetDate: pm.targetDate,
    targetMileageKm: pm.targetMileageKm,
    status: pm.status,
    constraintStart: pm.constraintStart,
    constraintEnd: pm.constraintEnd,
    assignedDepot: pm.assignedDepot
      ? {
          id: pm.assignedDepot.id,
          code: pm.assignedDepot.code,
        }
      : null,
    assignedTrack: pm.assignedTrack
      ? {
          id: pm.assignedTrack.id,
          trackNumber: pm.assignedTrack.trackNumber,
          trackType: pm.assignedTrack.trackType,
        }
      : null,
    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
    isLocked: pm.isLocked ?? false,
    maximoWoId: pm.maximoWoId,
  }));

  return c.json(
    paginatedSuccess(
      data,
      {
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalItems,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /pm/schedule/:id
 *
 * Get PM schedule details by ID.
 */
pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const service = getService();
  const pmResult = await service.getPm(pmId);

  // Cast to include all query relations (service returns more than type declares)
  const pm = pmResult as typeof pmResult & {
    assignedDepot: { id: string; code: string; name: string } | null;
  };

  // Check material availability for upcoming PMs
  let materialStatus = { allAvailable: true, warnings: [] as string[] };
  if (pm.status === 'SCHEDULED' && pm.assignedDepotId) {
    try {
      const materialResult = await service.checkMaterialAvailability(
        pm.pmTypeId,
        pm.assignedDepotId,
        pm.targetDate
      );
      materialStatus = {
        allAvailable: !materialResult.isBlocked && materialResult.softConstraintWarnings.length === 0,
        warnings: [
          ...materialResult.hardConstraintViolations.map((v) => `Blocked: ${v.partNumber} (need ${v.requiredQuantity}, have ${v.availableQuantity})`),
          ...materialResult.softConstraintWarnings.map((v) => `Warning: ${v.partNumber} may not be available`),
        ],
      };
    } catch {
      // Material check failed, assume available
    }
  }

  return c.json(
    success({
      id: pm.id,
      train: pm.train
        ? {
            id: pm.train.id,
            trainNumber: pm.train.trainNumber,
            fleetId: pm.train.fleetId,
          }
        : null,
      pmType: pm.pmType
        ? {
            id: pm.pmType.id,
            code: pm.pmType.pmCode,
            name: pm.pmType.pmName,
            estimatedHours: pm.pmType.estimatedHours,
          }
        : null,
      targetDate: pm.targetDate,
      targetMileageKm: pm.targetMileageKm,
      status: pm.status,
      constraintStart: pm.constraintStart,
      constraintEnd: pm.constraintEnd,
      assignedDepot: pm.assignedDepot
        ? {
            id: pm.assignedDepot.id,
            code: pm.assignedDepot.code,
            name: pm.assignedDepot.name,
          }
        : null,
      assignedTrack: pm.assignedTrack
        ? {
            id: pm.assignedTrack.id,
            trackNumber: pm.assignedTrack.trackNumber,
            trackType: pm.assignedTrack.trackType,
          }
        : null,
      assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
      assignedShift: pm.assignedShift,
      isLocked: pm.isLocked ?? false,
      lockedReason: pm.lockedReason,
      maximoWoId: pm.maximoWoId,
      materialStatus,
      actualStartDate: pm.actualStartDate,
      actualEndDate: pm.actualEndDate,
      actualHours: pm.actualHours ? Number(pm.actualHours) : null,
      completedAt: pm.completedAt,
      completedMileageKm: pm.completedMileageKm,
      createdAt: pm.createdAt,
      updatedAt: pm.updatedAt,
    })
  );
});

/**
 * POST /pm/schedule
 *
 * Create a new PM schedule entry.
 *
 * Request body:
 * - trainId: UUID of train
 * - pmTypeId: UUID of PM type
 * - targetDate: Target date (YYYY-MM-DD)
 * - assignedDepotId?: UUID of assigned depot
 * - assignedTrackId?: UUID of assigned track
 * - scenarioId?: UUID of scenario (null for production)
 * - reason?: Reason for manual scheduling
 */
pmScheduleRoutes.post('/pm/schedule', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  // Validate required fields
  if (!body.trainId || !isValidUuid(body.trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'trainId is required and must be a valid UUID', requestId), 400);
  }
  if (!body.pmTypeId || !isValidUuid(body.pmTypeId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'pmTypeId is required and must be a valid UUID', requestId), 400);
  }
  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
  }

  // Validate optional UUIDs
  if (body.assignedDepotId && !isValidUuid(body.assignedDepotId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedDepotId must be a valid UUID', requestId), 400);
  }
  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
  }

  const service = getService();
  const user = c.get('user');

  const request: SchedulePmRequest = {
    trainId: body.trainId,
    pmTypeId: body.pmTypeId,
    targetDate: body.targetDate,
    assignedDepotId: body.assignedDepotId,
    assignedTrackId: body.assignedTrackId,
    assignedShift: body.assignedShift,
    notes: body.reason,
    createdBy: user?.id,
  };

  const created = await service.schedulePm(request);

  return c.json(
    success({
      id: created.id,
      trainId: created.trainId,
      pmTypeId: created.pmTypeId,
      targetDate: created.targetDate,
      targetMileageKm: created.targetMileageKm,
      status: created.status,
      constraintStart: created.constraintStart,
      constraintEnd: created.constraintEnd,
      assignedDepotId: created.assignedDepotId,
      assignedTrackId: created.assignedTrackId,
      assignedHours: created.assignedHours ? Number(created.assignedHours) : null,
      createdAt: created.createdAt,
    }),
    201
  );
});

/**
 * PATCH /pm/schedule/:id
 *
 * Update a PM schedule entry (move, reassign).
 *
 * Request body:
 * - targetDate?: New target date
 * - assignedTrackId?: New track assignment
 * - reason: Reason for change (required)
 */
pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Validate reason is provided
  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
  }

  // Validate targetDate if provided
  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
  }

  // Validate assignedTrackId if provided
  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
  }

  const service = getService();
  const user = c.get('user');

  // Get current PM to capture old values
  const currentPm = await service.getPm(pmId);

  // Only proceed if targetDate is being changed
  if (!body.targetDate) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
  }

  const request: MovePmRequest = {
    pmScheduleId: pmId,
    newTargetDate: body.targetDate,
    newTrackId: body.assignedTrackId,
    reason: body.reason,
    movedBy: user?.id ?? SYSTEM_USER_ID,
  };

  const updated = await service.movePm(request);

  // Calculate impact assessment
  let manhourImpact = 0;
  let conflictsCreated = 0;

  // Calculate man-hour impact if depot is assigned
  const depotId = updated.assignedDepotId ?? currentPm.assignedDepotId;
  if (depotId) {
    const estimatedHours = parseFloat(currentPm.pmType?.estimatedHours ?? '0');
    const manHourSvc = getManHourService();

    // Get old and new week utilization
    // When PM moves, it removes hours from old week and adds to new week
    const [oldWeekCapacity, newWeekCapacity] = await Promise.all([
      manHourSvc.checkLaborCapacity(depotId, currentPm.targetDate, 0),
      manHourSvc.checkLaborCapacity(depotId, updated.targetDate, estimatedHours),
    ]);

    // Impact is the change in new week's utilization
    // Positive = increased load, Negative = decreased load
    manhourImpact = Math.round(
      (newWeekCapacity.utilizationPct - oldWeekCapacity.utilizationPct) * 100
    ) / 100;
  }

  // Conflicts check: movePm already validates and throws on track conflicts
  // If we reach here, no new conflicts were created
  // The value 0 is correct - if there were conflicts, movePm would have thrown
  conflictsCreated = 0;

  const impactAssessment = {
    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
      ? 'WITHIN_WINDOW'
      : 'OUTSIDE_WINDOW',
    manhourImpact,
    conflictsCreated,
  };

  // Broadcast PM update to all connected canvas subscribers
  const hub = getWebSocketHub();
  hub.broadcastPmUpdated({
    pmId: updated.id,
    trainId: updated.trainId,
    trainNumber: currentPm.train?.trainNumber ?? 'Unknown',
    changes: [
      { field: 'targetDate', oldValue: currentPm.targetDate, newValue: updated.targetDate },
      ...(body.assignedTrackId && body.assignedTrackId !== currentPm.assignedTrackId
        ? [{ field: 'assignedTrackId', oldValue: currentPm.assignedTrackId, newValue: body.assignedTrackId }]
        : []),
    ],
    changedBy: {
      userId: user?.id ?? SYSTEM_USER_ID,
      displayName: user?.email ?? 'System',
    },
  });

  return c.json(
    success({
      id: updated.id,
      targetDate: updated.targetDate,
      previousTargetDate: currentPm.targetDate,
      assignedTrackId: updated.assignedTrackId,
      previousTrackId: currentPm.assignedTrackId,
      updatedAt: updated.updatedAt,
      updatedBy: user?.id,
      explanation: {
        changeType: 'DATE_CHANGED',
        reason: body.reason,
        impactAssessment,
      },
    })
  );
});

/**
 * POST /pm/schedule/:id/validate-move
 *
 * Validate a PM move without committing changes.
 * Returns constraint violations for real-time drag feedback.
 *
 * Request body:
 * - targetDate: New target date (YYYY-MM-DD)
 * - trainId: Train ID (for service demand check)
 */
pmScheduleRoutes.post('/pm/schedule/:id/validate-move', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const body = await c.req.json();

  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
  }

  const service = getService();
  const violations: Array<{
    type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
    severity: 'ERROR' | 'WARNING';
    message: string;
  }> = [];

  try {
    // Get existing PM with relations
    const pm = await service.getPm(pmId);
    const targetDate = body.targetDate;

    // 1. Check Maximo lock
    const lockStatus = await service.checkMaximoLock(pmId);
    if (lockStatus.isLocked) {
      violations.push({
        type: 'MAXIMO_LOCK',
        severity: 'ERROR',
        message: lockStatus.reason ?? 'PM is locked and cannot be moved',
      });
    }

    // 2. Check PM status
    if (pm.status !== 'SCHEDULED') {
      violations.push({
        type: 'MAXIMO_LOCK',
        severity: 'ERROR',
        message: `PM cannot be moved: status is ${pm.status}`,
      });
    }

    // 3. Check compliance window
    if (targetDate < pm.constraintStart) {
      violations.push({
        type: 'COMPLIANCE_WINDOW',
        severity: 'ERROR',
        message: `Target date ${targetDate} is before compliance window start (${pm.constraintStart})`,
      });
    }

    if (targetDate > pm.constraintEnd) {
      violations.push({
        type: 'COMPLIANCE_WINDOW',
        severity: 'ERROR',
        message: `Target date ${targetDate} is after compliance window end (${pm.constraintEnd})`,
      });
    }

    // 4. Check track conflict (if track is assigned)
    if (pm.assignedTrackId) {
      const durationDays = pm.pmType?.minTrackDays ?? 1;
      const conflict = await service.checkTrackConflict(
        pm.assignedTrackId,
        targetDate,
        durationDays,
        pmId
      );

      if (conflict) {
        violations.push({
          type: 'TRACK_CONFLICT',
          severity: 'WARNING',
          message: `Track is occupied on ${targetDate} by another PM`,
        });
      }
    }

    // 5. Check material availability (if depot assigned)
    if (pm.assignedDepotId) {
      const materialResult = await service.checkMaterialAvailability(
        pm.pmTypeId,
        pm.assignedDepotId,
        targetDate
      );

      if (materialResult.isBlocked) {
        const missingParts = materialResult.hardConstraintViolations
          .map((v) => v.partNumber)
          .join(', ');
        violations.push({
          type: 'MATERIAL',
          severity: 'ERROR',
          message: `Missing critical parts: ${missingParts}`,
        });
      } else if (materialResult.softConstraintWarnings.length > 0) {
        violations.push({
          type: 'MATERIAL',
          severity: 'WARNING',
          message: `${materialResult.softConstraintWarnings.length} parts may not be available`,
        });
      }
    }

    // 6. Check service demand (need serviceDemandService)
    // Service demand is checked by the pm-scheduler service internally
    // For validation, we import and use it here
    const trainId = body.trainId ?? pm.trainId;
    const { getServiceDemandService } = await import('../../services');
    const serviceDemandService = getServiceDemandService();
    const { canSchedule, validation } = await serviceDemandService.canScheduleTrainForMaintenance(
      trainId,
      targetDate
    );

    if (!canSchedule) {
      violations.push({
        type: 'SERVICE_DEMAND',
        severity: 'ERROR',
        message: validation.message,
      });
    }

    const hasErrors = violations.some((v) => v.severity === 'ERROR');

    return c.json(
      success({
        isValid: !hasErrors,
        violations,
      })
    );
  } catch (err) {
    // If PM not found or other error
    const message = err instanceof Error ? err.message : 'Validation failed';
    return c.json(error(ErrorCodes.NOT_FOUND, message, requestId), 404);
  }
});

/**
 * POST /pm/schedule/:id/move-impact
 *
 * Get detailed impact assessment for a PM move.
 * Used for the confirmation dialog before committing.
 *
 * Request body:
 * - targetDate: New target date (YYYY-MM-DD)
 * - currentDate: Current target date (YYYY-MM-DD)
 */
pmScheduleRoutes.post('/pm/schedule/:id/move-impact', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const body = await c.req.json();

  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
  }

  if (!body.currentDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.currentDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'currentDate is required and must be in YYYY-MM-DD format', requestId), 400);
  }

  const service = getService();
  const manHourSvc = getManHourService();

  try {
    const pm = await service.getPm(pmId);
    const targetDate = body.targetDate;
    const currentDate = body.currentDate;

    // Calculate man-hour changes
    const depotId = pm.assignedDepotId;
    const estimatedHours = parseFloat(pm.pmType?.estimatedHours ?? '0');

    let manhourChange = {
      sourceWeek: { required: 0, available: 0 },
      targetWeek: { required: 0, available: 0 },
    };

    if (depotId) {
      // Get source week capacity (current date, removing the PM hours)
      const sourceWeek = await manHourSvc.checkLaborCapacity(depotId, currentDate, 0);

      // Get target week capacity (new date, adding the PM hours)
      const targetWeek = await manHourSvc.checkLaborCapacity(depotId, targetDate, estimatedHours);

      manhourChange = {
        sourceWeek: {
          required: Math.round(sourceWeek.totalRequiredHours - estimatedHours),
          available: sourceWeek.availableHours.total,
        },
        targetWeek: {
          required: Math.round(targetWeek.totalRequiredHours),
          available: targetWeek.availableHours.total,
        },
      };
    }

    // Calculate cost change (based on labor hours and rate)
    // Simple estimate: same PM, no cost change unless overtime required
    const targetUtilization = manhourChange.targetWeek.available > 0
      ? manhourChange.targetWeek.required / manhourChange.targetWeek.available
      : 0;
    const overtimeThreshold = 0.9; // 90% utilization triggers overtime
    const overtimeRate = 1.5; // 50% premium
    const hourlyRate = 350; // HKD per hour (configurable)

    let costChange = 0;
    if (targetUtilization > overtimeThreshold && manhourChange.targetWeek.available > 0) {
      // Overtime hours needed
      const overtimeHours = Math.max(
        0,
        manhourChange.targetWeek.required - (manhourChange.targetWeek.available * overtimeThreshold)
      );
      costChange = Math.round(overtimeHours * hourlyRate * (overtimeRate - 1));
    }

    // Check for track conflicts created
    const conflictsCreated: string[] = [];
    if (pm.assignedTrackId) {
      const durationDays = pm.pmType?.minTrackDays ?? 1;
      const conflict = await service.checkTrackConflict(
        pm.assignedTrackId,
        targetDate,
        durationDays,
        pmId
      );

      if (conflict) {
        conflictsCreated.push(`Track conflict with PM ${conflict.id} on ${conflict.targetDate}`);
      }
    }

    // Calculate drift from baseline (if baseline exists)
    let driftFromBaseline = 0;
    try {
      // Query for the most recent published baseline that includes this PM's train and PM type
      const { baselinePmSchedule, planBaselines } = await import('../../lib/db/schema');

      // Find latest published baseline
      const latestBaseline = await db.query.planBaselines.findFirst({
        where: eq(planBaselines.status, 'PUBLISHED'),
        orderBy: desc(planBaselines.publishedAt),
      });

      if (latestBaseline) {
        // Find this PM's baseline entry
        const baselineEntry = await db.query.baselinePmSchedule.findFirst({
          where: and(
            eq(baselinePmSchedule.baselineId, latestBaseline.id),
            eq(baselinePmSchedule.trainId, pm.trainId),
            eq(baselinePmSchedule.pmTypeId, pm.pmTypeId)
          ),
        });

        if (baselineEntry && baselineEntry.projectedDate) {
          const baselineDateObj = new Date(baselineEntry.projectedDate);
          const targetDateObj = new Date(targetDate);
          driftFromBaseline = Math.round(
            (targetDateObj.getTime() - baselineDateObj.getTime()) / (1000 * 60 * 60 * 24)
          );
        }
      }
    } catch {
      // Baseline check failed, default to 0 drift
      driftFromBaseline = 0;
    }

    return c.json(
      success({
        manhourChange,
        costChange,
        conflictsCreated,
        driftFromBaseline,
      })
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Impact assessment failed';
    return c.json(error(ErrorCodes.NOT_FOUND, message, requestId), 404);
  }
});

/**
 * POST /pm/schedule/:id/lock
 *
 * Lock a PM to prevent optimizer changes.
 *
 * Request body:
 * - reason: Reason for locking (required)
 */
pmScheduleRoutes.post('/pm/schedule/:id/lock', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const body = await c.req.json();

  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for locking', requestId), 400);
  }

  const service = getService();
  const user = c.get('user');

  // Get PM with train details for broadcast
  const pm = await service.getPm(pmId);

  const updated = await service.lockPm(pmId, body.reason, user?.id ?? SYSTEM_USER_ID);

  // Broadcast lock event to all connected canvas subscribers
  const hub = getWebSocketHub();
  hub.broadcastPmLocked({
    pmId: updated.id,
    trainId: pm.trainId,
    trainNumber: pm.train?.trainNumber ?? 'Unknown',
    isLocked: true,
    lockedReason: body.reason,
    lockedBy: {
      userId: user?.id ?? SYSTEM_USER_ID,
      displayName: user?.email ?? 'System',
    },
  });

  return c.json(
    success({
      id: updated.id,
      isLocked: updated.isLocked,
      lockedReason: updated.lockedReason,
      lockedBy: updated.lockedBy,
      lockedAt: updated.lockedAt,
    })
  );
});

/**
 * POST /pm/schedule/:id/unlock
 *
 * Unlock a PM to allow optimizer changes.
 */
pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const service = getService();
  const user = c.get('user');

  // Get PM with train details for broadcast
  const pm = await service.getPm(pmId);

  const updated = await service.unlockPm(pmId, user?.id ?? SYSTEM_USER_ID);

  // Broadcast unlock event to all connected canvas subscribers
  const hub = getWebSocketHub();
  hub.broadcastPmLocked({
    pmId: updated.id,
    trainId: pm.trainId,
    trainNumber: pm.train?.trainNumber ?? 'Unknown',
    isLocked: false,
    lockedBy: {
      userId: user?.id ?? SYSTEM_USER_ID,
      displayName: user?.email ?? 'System',
    },
  });

  return c.json(
    success({
      id: updated.id,
      isLocked: updated.isLocked,
      lockedReason: updated.lockedReason,
      lockedBy: updated.lockedBy,
      lockedAt: updated.lockedAt,
    })
  );
});

/**
 * GET /pm/schedule/:id/history
 *
 * Get change history for a PM.
 */
pmScheduleRoutes.get('/pm/schedule/:id/history', async (c) => {
  const requestId = getRequestId(c);
  const pmId = c.req.param('id');

  if (!isValidUuid(pmId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
  }

  const service = getService();
  const history = await service.getPmHistory(pmId);

  const data = history.map((entry) => ({
    id: entry.id,
    changeType: entry.changeType,
    oldTargetDate: entry.oldTargetDate,
    newTargetDate: entry.newTargetDate,
    oldStatus: entry.oldStatus,
    newStatus: entry.newStatus,
    oldAssignedTrackId: entry.oldAssignedTrackId,
    newAssignedTrackId: entry.newAssignedTrackId,
    changedBy: entry.changedByUser
      ? {
          id: entry.changedByUser.id,
          displayName: entry.changedByUser.displayName,
        }
      : null,
    changedAt: entry.changedAt,
    changeReason: entry.changeReason,
    changeSource: entry.changeSource,
  }));

  return c.json(success(data));
});

